"""
MKT Original Language Commentary -- John chapters 19-21
Run: python3 scripts/zc-original-john-19-21.py

Source data used:
- data/interlinear/john.json (chapters 19-21 tokens)
- data/translation/glossary-greek.json (semantic ranges, dispute levels)
- data/translation/draft/mediating/john.json (MKT text for reference)
- data/commentary/ellicott/john.json (philological source)

Key decisions in this range:
- "the Evangelist" continues as authorial designation throughout
- tetelestai (19:30) treated as commercial/legal/priestly completion -- telew
  discharges a debt or obligation, not merely ends a process
- paredwken to pneuma (19:30): ambiguity preserved -- "handed over the spirit"
  carries both the sense of expiry and of deliberate transmission (cf. 14:16)
- haima kai hydwr (19:34): the order and the eyewitness note (19:35) flagged as
  deliberately theological; not purely medical
- enephysesen (20:22): noted as Gen 2:7 echo; the aorist imperative "receive"
  distinguishes this from Pentecost; not harmonized with Acts 2
- me mou haptou (20:17): "do not hold on to me" rather than "do not touch" --
  haptesthai implies clinging; perfect anabebeka treated as proleptically future
- agapas / phileis distinction (21:15-17): both the traditional distinction and
  the counter-argument (Johannine synonym use) are noted; the structural shift
  where Jesus adopts Peter's word on the third question is given weight regardless
- 153 fish (21:11): the numerical speculation (Jerome, triangular numbers) noted
  but not asserted; the Evangelist's interest appears to be eyewitness precision
- ou moi auton (21:22): Jesus's conditional phrasing treated as a deliberate
  non-answer, not a promise of longevity
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOHN = {
  "19": {
    "1": '<p><strong>ἐμαστίγωσεν</strong> -- the verb is the standard term for Roman <em>flagellatio</em>, flogging with a leather scourge weighted with lead or bone. This was distinct from the Jewish synagogue punishment of thirty-nine lashes. Roman flogging was not regulated by Jewish law and could be lethal. The Evangelist records it in a single verb -- the severity is implied, not narrated.</p>',
    "2": '<p><strong>ἐκ ἀκανθῶν στέφανον</strong> -- a crown of thorns (<em>akanthon stephanon</em>). The word <em>stephanon</em> is the victor\'s or ruler\'s wreath, not the diadem of royalty. The soldiers use the symbol of honor to enact mockery; the Evangelist lets the irony speak without comment. The purple (<em>porfyroûn</em>) robe signifies royalty and maps onto the imperial purple -- soldiers likely commandeered a legionary cloak.</p>',
    "3": '<p><strong>ἐρράπιζον</strong> -- the imperfect tense marks repeated action: they kept striking. The mocking address "Hail, King of the Jews" (<em>Chairé, ho Basileùs tōn Ioudaíōn</em>) directly parodies the imperial salute <em>Ave Caesar</em>. The irony the Evangelist sustains throughout the trial scenes is intensified here: the soldiers performing mockery are, unknowingly, enacting a throne-room investiture.</p>',
    "4": '<p><strong>οὐδεμίαν αἰτίαν εὑρίσκω</strong> -- "I find no charge" (<em>aitían</em>). This is Pilate\'s third formal declaration of innocence (cf. 18:38; 19:6). The triple-repeated acquittal by Rome\'s representative is structurally significant: it functions as a legal refrain. The Evangelist uses the verb <em>heuriskō</em> (find by investigation) rather than a simple negative assertion -- Pilate has looked and concluded.</p>',
    "5": '<p><strong>Ἰδοὺ ὁ ἄνθρωπος</strong> -- "Behold the man!" This famous pronouncement (<em>Ecce homo</em>) is unique to John. The phrase is ambiguous: Pilate intends it as an appeal to pity, but the Evangelist\'s presentation of Jesus as the Logos-made-flesh gives <em>ho anthrōpos</em> its fullest weight -- this is the human one, in whom God is disclosed. The same <em>Idou</em> construction echoes the Baptist\'s "Behold, the Lamb of God" (1:36).</p>',
    "6": '<p><strong>Σταύρωσον σταύρωσον</strong> -- the double imperative without connective (<em>asyndeton</em>) conveys urgency and crowd pressure. Pilate\'s response -- "take him yourselves and crucify him" -- is a taunt: Roman law gave Jews no authority to execute. The formal capitulation does not come until v.16. The repetition of <em>ouk heuriskō</em> (I find no charge) is the Evangelist\'s fourth record of this verdict within two chapters.</p>',
    "7": '<p><strong>υἱὸν θεοῦ</strong> -- "Son of God" -- the charge now shifts from political to blasphemy. The definite article is absent (<em>huion theou</em>, not <em>ton huion tou theou</em>), though in context the anarthrous construction does not necessarily denote a lesser claim. The Jewish leaders cite their law -- <em>katà tòn nómon hēmōn</em> -- invoking Lev 24:16 (blasphemy deserves death). This is the charge that produces Pilate\'s fear in v.8.</p>',
    "8": '<p><strong>μᾶλλον ἐφοβήθη</strong> -- "was more afraid" -- the comparative <em>mâllon</em> signals that Pilate was already afraid (cf. the repeated attempts to release Jesus), and the charge of divine sonship deepens it. The Evangelist does not explain Pilate\'s fear; its cause is left open. Whether superstitious dread of a divine figure, political caution, or something else, the narrative withholds psychological closure.</p>',
    "9": '<p><strong>πόθεν εἶ σύ</strong> -- "Where are you from?" The question is one the Evangelist has already answered for the reader (1:1-14; 8:23) but Pilate cannot know. Jesus\'s silence -- <em>apokrisin ouk edōken</em>, gave no answer -- echoes the Servant of Isa 53:7 ("he did not open his mouth"). The refusal to answer Pilate stands in contrast to Jesus\'s extensive dialogue with him in 18:33-38.</p>',
    "10": '<p><strong>ἐξουσίαν ἔχω</strong> -- Pilate twice claims <em>exousían</em> (authority, delegated right) -- to release and to crucify. The word recurs in v.11 where Jesus subordinates it. <em>Exousía</em> is not raw capacity but official standing; Pilate\'s error is treating it as autonomous rather than derived.</p>',
    "11": '<p><strong>ἄνωθεν</strong> -- "from above" -- the same word used in 3:3 and 3:31. Pilate\'s authority is delegated from God (<em>anōthen</em>), not self-derived. Jesus\'s statement does not acquit Pilate; it calibrates guilt. The one who delivered Jesus to Pilate (<em>ho paradous</em>) bears the greater sin -- the reference is ambiguous (Caiaphas? Judas? the chief priests as a group?) and the Evangelist likely intends the ambiguity to be felt.</p>',
    "12": '<p><strong>φίλος τοῦ Καίσαρος</strong> -- "friend of Caesar" (<em>Kaisaros philos</em>) was a formal designation of loyalty and favor, not merely a colloquial term. Losing this status had real political and economic consequences. The accusation -- that releasing Jesus makes Pilate disloyal to the emperor -- converts a theological dispute into a political threat. The shift in strategy (from religious charge to treason) is noted by the Evangelist without comment.</p>',
    "13": '<p><strong>Γαββαθά</strong> -- <em>Gabbathâ</em>, the Aramaic name for the stone pavement (<em>Lithostroton</em>). John includes dual designations (Greek and Aramaic) as he does for Golgotha and other place names, consistent with the multilingual context of Jerusalem. The <em>bēma</em> (judgment seat) was the official platform for pronouncing sentences; Pilate sitting on it makes the trial formal and the verdict legally binding.</p>',
    "14": '<p><strong>ὥρα ἦν ὡς ἕκτη</strong> -- "about the sixth hour" -- approximately noon. This creates a tension with Mark 15:25, which places the crucifixion at the third hour. Various harmonization attempts exist (different reckoning systems; "about" absorbing the gap). The Evangelist may also have a theological interest: noon is when the Passover lambs began to be slaughtered in the temple. The resonance with 1:29 and 19:36 is available to the reader.</p>',
    "15": '<p><strong>Οὐκ ἔχομεν βασιλέα εἰ μὴ Καίσαρα</strong> -- "We have no king but Caesar." The Evangelist presents this as the climactic self-declaration of the chief priests. In Jewish theological terms, YHWH alone is Israel\'s king (1 Sam 8:7; Isa 26:13). The priests\' answer formally repudiates that kingship. The statement is theologically catastrophic in a way that the narrative renders plainly; no commentary is added by the Evangelist -- the irony is structural.</p>',
    "16": '<p><strong>παρέδωκεν αὐτὸν</strong> -- "handed him over" -- the verb <em>paradidōmi</em> has appeared throughout the passion narrative for Judas\'s betrayal (6:71; 13:2) and now for Pilate\'s capitulation. The repeated handover language signals a chain of delegation: Judas to the priests, priests to Pilate, Pilate to the soldiers. Against the backdrop of Jesus\'s own words (10:18: "I lay down my life of myself") the Evangelist sustains the paradox -- the one delivered controls the delivery.</p>',
    "17": '<p><strong>βαστάζων ἑαυτῷ τὸν σταυρόν</strong> -- "bearing his cross himself" -- the Evangelist omits Simon of Cyrene (present in all three Synoptics). The deliberate use of <em>heautō</em> (for himself) foregrounds Jesus\'s agency. In context of 12:24-26 (where taking up the cross is discipleship language) the Evangelist presents the scene as an enacted parable of what Jesus has been teaching.</p>',
    "18": '<p><strong>ἐσταύρωσαν</strong> -- the verb is aorist; the act is stated without elaboration. The Evangelist does not describe the physical procedure of crucifixion. What he notes is position: Jesus in the middle (<em>meson</em>), the two others on either side. The placement echoes no single text but the repeated centrality of Jesus in the passion narrative frames the detail theologically.</p>',
    "19": '<p><strong>τίτλον</strong> -- the Latin loanword <em>titlon</em> (<em>titulus</em>) was the wooden board listing the criminal\'s name and offense, carried before the prisoner or affixed to the cross. Its content -- JESUS OF NAZARETH, THE KING OF THE JEWS -- is identical across all four Gospels with minor variation. The Evangelist names Pilate as the author (<em>egrapse</em>, wrote), placing the ironic proclamation as Pilate\'s formal act.</p>',
    "20": '<p><strong>Ἑβραϊστί, Ῥωμαϊστί, Ἑλληνιστί</strong> -- Aramaic, Latin, and Greek. The three languages represent the entire cultural world of the province: Jewish religion, Roman law, Greek culture. The trilingual proclamation of Jesus as king over all three spheres is noted only in John. The location\'s proximity to the city meant the inscription was read by many -- it was, in effect, a public announcement.</p>',
    "21": '<p><strong>μὴ γράφε</strong> -- "do not write" -- present imperative with <em>mē</em> stops an ongoing action: the inscription already stands. The chief priests want it revised to a reported claim, not a declaration. Pilate\'s refusal signals -- whatever his intent -- the Evangelist\'s conviction that what is written stands.</p>',
    "22": '<p><strong>Ὃ γέγραφα γέγραφα</strong> -- "What I have written, I have written." The repeated perfect tense (<em>gegráphe</em> -- "it stands written") conveys finality: a past act whose result endures. The Greek perfect is the Evangelist\'s tense for permanent, irreversible action (cf. 19:28; 20:23). The phrase has become proverbial for irrevocability; the Evangelist gives Pilate the last word because it is, in theological terms, the correct answer.</p>',
    "23": '<p><strong>ἄραφος</strong> -- "without seam, woven from the top throughout" -- the seamless garment. The detail is unique to John. Josephus describes the high-priestly robe as similarly seamless (<em>Ant.</em> 3.161); the Evangelist\'s audience would register the resonance without needing it spelled out. The soldiers\' refusal to divide it -- <em>mē schisōmen</em>, let us not tear -- fulfills Ps 22:18, cited in v.24.</p>',
    "24": '<p><strong>ἵνα ἡ γραφὴ πληρωθῇ</strong> -- fulfillment formula. The citation is Ps 22:18 (LXX 21:19): "they divided my garments among them and cast lots for my clothing." The Evangelist uses the fulfillment formula more densely in the passion than anywhere else in the Gospel. The two-part action -- dividing the garments and casting lots -- corresponds to the two clauses of the psalm, which is Hebrew synonymous parallelism. The soldiers enact both clauses literally.</p>',
    "25": '<p><strong>εἱστήκεισαν δὲ παρὰ τῷ σταυρῷ</strong> -- "standing by the cross" -- the pluperfect <em>heistēkeisan</em> indicates sustained presence; they had been standing there and continued to stand. Four women are named, though the relationship of "his mother\'s sister" to "Mary the wife of Clopas" is disputed (two women or four?). The contrast with the male disciples who fled (18:8) is implied but not stated.</p>',
    "26": '<p><strong>Γύναι, ἴδε ὁ υἱός σου</strong> -- "Woman, behold your son." The address <em>Gynai</em> (Woman) is the same form used at Cana (2:4) and marks a significant moment in both cases. It is not a diminishment in Greek; it is a formal address of a social equal. The Evangelist notes the presence of the Beloved Disciple here for the transfer of filial responsibility -- a legal and social act carried out from the cross.</p>',
    "27": '<p><strong>εἰς τὰ ἴδια</strong> -- "into his own home" (or "his own things/household"). The phrase is identical to 1:11 -- "his own people did not receive him" -- a deliberate echo: the Beloved Disciple receives what the nation did not. The taking in of Jesus\'s mother is both a practical provision and a theological statement about the community formed by the cross.</p>',
    "28": '<p><strong>τετέλεσται</strong> -- "it is finished/accomplished" -- here the Evangelist uses a subordinated clause: "knowing that all things were now finished" (<em>ēdē panta tetelestai</em>). The verb <em>teleioō</em> (16:23; 17:4) has been used for completion of the Father\'s work; now <em>teleō</em> (G5055) marks the discharge of an obligation. <strong>Διψῶ</strong> -- "I thirst" -- stated so that scripture might be fulfilled; identified with Ps 22:15 and Ps 69:21 (vinegar given to the thirsty).</p>',
    "29": '<p><strong>ὑσσώπῳ</strong> -- hyssop (<em>hyssōpō</em>). The detail is significant: in Exod 12:22 hyssop is the instrument for applying the Passover blood to the doorposts. John\'s passion narrative has been structured around Passover throughout; the hyssop at the cross draws the line back to the Exodus deliverance. Mark and Matthew specify a reed (<em>kalamos</em>); the Evangelist\'s choice of hyssop is almost certainly deliberate.</p>',
    "30": '<p><strong>Τετέλεσται</strong> -- "It is finished." The verb <em>teleō</em> (G5055) means to complete, discharge, or conclude -- particularly the discharge of a debt or obligation. The word was used in commercial and legal contexts for a payment fully made. The Evangelist\'s single Greek word is the theological apex of the passion narrative: everything the Father commissioned (4:34; 17:4) is now brought to its end.</p><p><strong>παρέδωκεν τὸ πνεῦμα</strong> -- "handed over the spirit." The verb <em>paradidōmi</em> is the same chain-of-handover word used for Judas, for Pilate, and now here. The expression for dying in Greek idiom is typically <em>ekpneō</em> (breathe out) or <em>aphiēmi</em>; <em>paradidōmi</em> implies a deliberate act of transmission. Whether the Evangelist intends a reference to the Spirit given to the disciples (cf. 20:22) is debated, but the choice of verb is not accidental.</p>',
    "31": '<p><strong>παρασκευή</strong> -- "preparation" (day before the Sabbath). The Evangelist\'s chronology places the death on Preparation Day, making it Passover Eve (14 Nisan) -- distinct from the Synoptics where the Last Supper appears to be the Passover meal. For the Evangelist, Jesus dies as the lambs are being prepared, which coheres with 1:29 and the structuring of the passion around the Passover lamb.</p><p><strong>μεγάλη ἡ ἡμέρα</strong> -- "great day" -- this Sabbath coincided with Passover, making it doubly significant. The request to break legs (<em>kataxōsin</em>) and remove bodies is motivated by Deut 21:22-23 (a hanged man\'s body must not remain overnight).</p>',
    "32": '<p>Transitional narrative. The soldiers break the legs of the two crucified with Jesus. The Evangelist notes this to establish the contrast with what they find when they come to Jesus in v.33.</p>',
    "33": '<p><strong>ἤδη αὐτὸν τεθνηκότα</strong> -- "already dead" -- the perfect participle <em>tethnēkota</em> marks the completed state of death. The Evangelist underlines that Jesus was verifiably dead before the spear thrust; there is no ambiguity. The soldiers (experienced executioners) confirm the fact by not breaking his legs.</p>',
    "34": '<p><strong>αἷμα καὶ ὕδωρ</strong> -- "blood and water." The Evangelist records both fluid components in a specific order. Various medical explanations have been proposed (pericardial effusion; post-mortem separation of blood). But the Evangelist frames this as theologically significant through the eyewitness note in v.35. The sacramental reading (Eucharist and baptism; cf. 1 John 5:6-8) is present in early Christian interpretation. The order -- blood first, then water -- is the same as 1 John 5:6: "not by water only but by water and blood."</p>',
    "35": '<p><strong>ὁ ἑωρακὼς μεμαρτύρηκεν</strong> -- "the one who has seen has testified." Both verbs are perfect tense: the seeing is a completed act whose result stands; the testimony is ongoing. The Evangelist speaks of himself in the third person -- consistent with his practice throughout (13:23; 19:26; 21:7; 21:20). The emphatic truthfulness claim (<em>alēthinē estin hē martyria autou</em>) has the character of a legal deposition, inserted precisely at the theologically loaded detail of blood and water.</p>',
    "36": '<p><strong>ὀστοῦν οὐ συντριβήσεται αὐτοῦ</strong> -- "a bone of him shall not be broken." The citation is from Exod 12:46 (and Num 9:12), the Passover lamb regulation. This is the only place in the NT where the Passover lamb connection is made explicit by citation rather than by typological implication. The fulfillment language (<em>hina plērōthēi</em>) frames it as deliberate divine design.</p>',
    "37": '<p><strong>ὄψονται εἰς ὃν ἐξεκέντησαν</strong> -- "they shall look on him whom they pierced." The citation is from Zech 12:10. The Evangelist follows a reading closer to the MT than the LXX (which has "they shall mourn for him"). The verb <em>ekkenteín</em> (to pierce through) is the same word used for the spear thrust in v.34 -- the translator\'s word choice made the connection between Zechariah and the passion scene verbally precise.</p>',
    "38": '<p><strong>κεκρυμμένος δὲ διὰ τὸν φόβον τῶν Ἰουδαίων</strong> -- "hidden because of the fear of the Jewish leaders." Joseph of Arimathea is introduced as a disciple (<em>mathētēs</em>) but a secret one. The Evangelist uses the same language as 12:42 (rulers who believed but did not confess "because of the Pharisees"). His public act of requesting the body amounts to the confession that his secrecy had previously prevented. The verb <em>ērōtēsen</em> (petitioned) is the same word used for prayer-petitions in the farewell discourses.</p>',
    "39": '<p><strong>μίγμα σμύρνης καὶ ἀλόης ὡς λίτρας ἑκατόν</strong> -- approximately seventy-five pounds. The quantity is extraordinary -- royal burial quantities. Nicodemus, introduced in 3:1 as coming to Jesus by night (<em>nyktós</em>), now comes openly. The Evangelist\'s interest in burial details -- quantity and quality of spices -- underlines the honoring of Jesus as a king, counterpointing the mockery of chs. 18-19.</p>',
    "40": '<p><strong>ὀθονίοις μετὰ τῶν ἀρωμάτων</strong> -- "linen cloths with the spices" -- the same noun <em>othonia</em> used for the burial cloths that Peter and the Beloved Disciple will find in 20:5-7. The Evangelist\'s precise terminology here prepares the careful reader for the significance of the arrangement of those cloths in the empty tomb.</p>',
    "41": '<p><strong>κῆπος</strong> -- "garden" (<em>kēpos</em>). Only John names the tomb location as within a garden. The garden setting at the end of the passion narrative echoes the garden of 18:1 (where Jesus was arrested) and carries the faint resonance of Eden -- a reading the Evangelist enables but does not press.</p>',
    "42": '<p><strong>διὰ τὴν παρασκευὴν τῶν Ἰουδαίων</strong> -- "because of the Jews\' preparation" -- the burial is done hastily in a nearby tomb. The new tomb (<em>kainós</em>, unused) is not a detail of poverty but of honor: a tomb used for no previous person is fitting for the one who had claimed no previous person came down from heaven (3:13).</p>'
  },
  "20": {
    "1": '<p><strong>τῇ μιᾷ τῶν σαββάτων</strong> -- "on the first day of the week" -- literally "on the one of the Sabbaths." The unusual Greek phrasing reflects the underlying Semitic idiom for day-count within the week. The "first day" becomes the day of resurrection; its recurrence in 20:19 and 26 marks it as the day of gathering -- the eventual pattern of Christian worship. <strong>σκοτίας ἔτι οὔσης</strong> -- "while it was still dark" -- the darkness is temporal but the Evangelist has made darkness a theological marker throughout the Gospel (1:5; 8:12; 13:30); its presence at the resurrection\'s beginning gives way to the discovery of the empty tomb.</p>',
    "2": '<p><strong>ἦραν τὸν κύριον</strong> -- "they have taken the Lord." Mary\'s assumption is grave robbery. The plural <em>oidamen</em> (we do not know) suggests she was not alone -- consistent with the Synoptic accounts -- though the Evangelist focuses on her. The "other disciple" (<em>ton allon mathētēn</em>) is introduced here for the first time in the resurrection narrative; the Evangelist maintains his pattern of referring to the Beloved Disciple by this circumlocution.</p>',
    "3": '<p>Brief connector. The two disciples set out together; their running to the tomb (vv.3-8) is narrated with unusual physical detail -- arrival order, entry order, objects seen -- suggesting an eyewitness source.</p>',
    "4": '<p><strong>προέδραμεν τάχιον τοῦ Πέτρου</strong> -- "outran Peter" -- the comparative <em>tachion</em> (more quickly) is precise and vivid. The detail serves no obvious theological purpose, which is itself an argument for its historical basis. The Beloved Disciple arrives first but does not enter; Peter enters immediately upon arrival (v.6).</p>',
    "5": '<p><strong>παρακύψας βλέπει κείμενα τὰ ὀθόνια</strong> -- "stooping down, sees the linen cloths lying." The verb <em>blepei</em> is the ordinary verb for visual perception; it contrasts with <em>theōrei</em> (observe/contemplate) used for Peter in v.6 and <em>eiden</em> (saw with understanding) for the Beloved Disciple in v.8. The Evangelist has a consistent pattern of using different seeing verbs for different depths of perception.</p>',
    "6": '<p><strong>θεωρεῖ τὰ ὀθόνια κείμενα</strong> -- Peter uses <em>theōrei</em> -- to observe, contemplate, take in. He sees the linen cloths and (v.7) the face-cloth separately arranged. The Evangelist does not record that Peter believed at this point; v.8 reserves that response for the Beloved Disciple. Peter\'s reaction is unnarrated -- left open.</p>',
    "7": '<p><strong>τὸ σουδάριον</strong> -- the napkin or face-cloth -- found not with the <em>othonia</em> (body wrappings) but separately, rolled up in its own place. This detail is central to the narrative\'s argument against grave robbery: a thief would not have taken the time to unwrap the body and arrange the cloths. The orderliness of the scene signals deliberate action. The word <em>entetyligmenon</em> (wrapped together, folded) carries the sense of a completed action left in a specific state.</p>',
    "8": '<p><strong>εἶδεν καὶ ἐπίστευσεν</strong> -- "saw and believed." The verb <em>eiden</em> here (G3708 root) implies perception that grasps significance. This is the Evangelist\'s description of the Beloved Disciple\'s Easter faith: he saw the empty tomb with its arranged grave-clothes and believed -- without a resurrection appearance, without fulfillment-Scripture citation. The parenthetical v.9 explains that the two disciples did not yet understand the resurrection from Scripture; the Beloved Disciple believed on physical evidence alone.</p>',
    "9": '<p><strong>οὐδέπω γὰρ ᾔδεισαν τὴν γραφήν</strong> -- "for they did not yet know the Scripture." The Evangelist inserts a parenthetical editorial note -- his characteristic device (cf. 2:21; 7:39; 12:16). The pluperfect <em>ēideisan</em> indicates that scriptural understanding came later; the disciples\' Easter faith preceded and was independent of their later biblical interpretation. Faith can precede full theological understanding.</p>',
    "10": '<p>Brief connector. The disciples return home. The narrative turns entirely to Mary\'s encounter, narrated in greater detail than either disciple\'s experience.</p>',
    "11": '<p><strong>εἱστήκει δὲ Μαριὰμ πρὸς τῷ μνημείῳ ἔξω κλαίουσα</strong> -- "Mary stood outside the tomb weeping." The pluperfect <em>heistēkei</em> marks her sustained, still posture against the disciples\' departure. The verb <em>klaiein</em> (weep, wail) is the same word used for the community\'s weeping at Lazarus\'s tomb (11:31-33), where Jesus himself wept. The parallelism is deliberate: in ch.11 Jesus raised another; here the women and disciples mourn Jesus himself.</p>',
    "12": '<p><strong>δύο ἀγγέλους ἐν λευκοῖς</strong> -- "two angels in white, sitting where the body of Jesus had lain." The Evangelist notes the positional detail -- one at the head, one at the feet -- of the divine messengers. The angels\' role in John is minimal: they do not announce the resurrection but ask Mary a question, drawing out her response.</p>',
    "13": '<p><strong>ἦραν τὸν κύριόν μου</strong> -- "they have taken away my Lord." Mary\'s personal possessive (<em>mou</em>) is striking -- language of personal relationship, not merely formal title. The Evangelist\'s consistent use of <em>kurios</em> (Lord) for the risen Jesus throughout ch.20 is a post-resurrection Christological datum; Mary\'s adoption of the title here is his earliest instance of it in the resurrection appearances.</p>',
    "14": '<p><strong>ἐστράφη εἰς τὰ ὀπίσω</strong> -- "turned around" -- Mary turns away from the angels to see Jesus standing behind her. The reason she does not recognize him (<em>ouk ēidei hoti Iēsous estin</em>) is unexplained. Non-recognition is a pattern in the resurrection appearances (20:14; Luke 24:16). The narrative focus is on the moment of recognition (v.16), not on explaining its absence.</p>',
    "15": '<p><strong>κηπουρός</strong> -- "gardener" (<em>kēpouros</em>), a unique NT <em>hapax legomenon</em>. The misidentification is dramatic irony: the reader knows who Jesus is. The Evangelist may also register the Eden resonance (cf. 19:41: the tomb is in a garden), though secondary to the simple narrative of non-recognition. Mary\'s offer to carry the body herself captures both her devotion and the impossibility of what she proposes.</p>',
    "16": '<p><strong>Μαριάμ</strong> -- Jesus speaks her name, and in the address she recognizes him. The Evangelist reports her response in Aramaic -- <em>Rabbounī</em> (Rabbouni), then provides the Greek gloss "which means Teacher." The Aramaic address is striking: this is the language of intimacy, the mother-tongue address. The scene echoes 10:3 ("the shepherd calls his own sheep by name"); the sheep know his voice.</p>',
    "17": '<p><strong>μή μου ἅπτου</strong> -- "stop holding onto me" -- the present imperative with <em>mē</em> stops an ongoing action: Mary has already grasped him. The verb <em>haptesthai</em> is not "touch" (which would be an aorist prohibition) but "cling to, hold." The reason given -- "for I have not yet ascended to the Father" -- implies the current state is transitional. The Evangelist offers no resolution of the theological difficulty.</p><p><strong>ἀναβαίνω</strong> -- the present tense ("I am ascending") -- not future. The resurrection and ascension are presented as a unified movement in the Fourth Gospel, not separated by forty days as in Acts 1. The message to "my brothers" (<em>tous adelphous mou</em>) is the first use of this fraternal language for the disciples in John.</p>',
    "18": '<p><strong>ἑώρακα τὸν κύριον</strong> -- "I have seen the Lord" -- perfect tense: a completed past act with present abiding significance. Mary becomes the first resurrection witness in John\'s account. The Evangelist notes that she reported what Jesus had said -- underscoring that her testimony included both the appearance and the words.</p>',
    "19": '<p><strong>εἰρήνη ὑμῖν</strong> -- "Peace to you" -- the standard Jewish greeting <em>shalom</em> / <em>eirēnē</em>, but freighted now with the content of the farewell discourses (14:27; 16:33). The greeting is given with doors locked -- <em>tōn thurōn kekleismenōn</em> (perfect participle, standing shut). Jesus\'s appearance does not depend on physical access; the Evangelist does not explain the mechanics, only the fact.</p>',
    "20": '<p><strong>ἔδειξεν τὰς χεῖρας καὶ τὴν πλευράν</strong> -- "showed them his hands and his side." The wounds are part of the identification -- the same body that was crucified is the body that is risen. The disciples\' response (<em>echarēsan</em>, rejoiced) fulfills 16:22: "your hearts will rejoice and no one will take your joy from you." The Evangelist marks the fulfillment with quiet precision.</p>',
    "21": '<p><strong>καθὼς ἀπέσταλκέν με ὁ πατήρ, κἀγὼ πέμπω ὑμᾶς</strong> -- "As the Father has sent me, so I send you." Two different verbs for "send": <em>apostellō</em> (Father\'s act, with its official, commissioned force) and <em>pempō</em> (Jesus\'s act, the more general sending). Whether the distinction is significant here is debated; the Evangelist uses both verbs for both Father and Son elsewhere. The mission of the disciples is explicitly modeled on and derived from the mission of the Son.</p>',
    "22": '<p><strong>ἐνεφύσησεν</strong> -- "breathed on them" -- a rare verb (<em>emphusaō</em>). The same word appears in the LXX of Gen 2:7, where God breathes into the nostrils of the man and he becomes a living being. The Evangelist\'s use of this word for Jesus\'s act is not accidental: the new creation parallels the first creation. The command <em>Labete Pneuma Hagion</em> -- "Receive Holy Spirit" (anarthrous, no definite article) -- is an aorist imperative. This is not the same event as Pentecost (Acts 2); the Evangelist presents a distinct bestowing. Harmonization with Acts is possible but the two accounts are not identical.</p>',
    "23": '<p><strong>ἄν τινων ἀφῆτε τὰς ἁμαρτίας</strong> -- "whoever\'s sins you forgive, they are forgiven." The authority communicated here is corporate and verbal -- the disciples are entrusted with the ministry of forgiveness and its withholding (<em>kratēte</em>, retain). The verbs are present tense in the consequence clause: forgiveness and retention are ongoing realities of the community\'s ministry. This commission is connected to the Holy Spirit\'s gift in v.22 -- the Spirit enables and authorizes the ministry.</p>',
    "24": '<p><strong>Θωμᾶς ὁ λεγόμενος Δίδυμος</strong> -- Thomas called Didymus (Twin in Aramaic and Greek respectively). The Evangelist introduces him with his dual-name designation (as in 11:16; 21:2) and notes his absence without explanation. His absence is narrative setup for the scene in vv.25-28; its cause is not supplied.</p>',
    "25": '<p><strong>ἐὰν μὴ ἴδω … οὐ μὴ πιστεύσω</strong> -- "unless I see... I will not believe" -- a strong double negative (<em>ou mē</em>) with subjunctive: the most emphatic negation in Greek. Thomas\'s demand for tangible evidence is often called skepticism, but the Evangelist presents it as the same desire all the disciples had already been given (v.20: Jesus showed them his hands and side). Thomas wants what the other disciples received. His demand is for consistency of evidence, not excess of doubt.</p>',
    "26": '<p><strong>μεθ᾽ ἡμέρας ὀκτώ</strong> -- "after eight days" -- one week later. The repeated "first day of the week" gathering (cf. v.19) is the beginning of what will become the pattern of the Lord\'s Day. Jesus again appears through locked doors with the same greeting -- <em>Eirēnē hymin</em> -- establishing a structural parallel. Thomas is now present.</p>',
    "27": '<p><strong>Φέρε τὸν δάκτυλόν σου ὧδε</strong> -- "Bring your finger here." Jesus addresses Thomas using the exact language of Thomas\'s demand (v.25): the nail marks, the side. The aorist imperatives <em>Phere</em> (bring!) and <em>Ide</em> (see!) are commands, not invitations. <strong>μὴ γίνου ἄπιστος ἀλλὰ πιστός</strong> -- "do not be faithless but faithful" -- the present imperative <em>ginou</em> commands a becoming, not merely a momentary act. Jesus\'s intervention is a summons to a state of faith.</p>',
    "28": '<p><strong>ὁ Κύριός μου καὶ ὁ Θεός μου</strong> -- "My Lord and my God!" This is the highest explicit Christological confession in the Gospel. Thomas does not merely address Jesus as Lord but adds <em>ho Theos mou</em> -- my God. The double article with the personal pronoun gives the affirmation its full confessional weight. Whether Thomas actually touches the wounds is not stated -- the Evangelist leaves this ambiguous.</p><p>The Evangelist has structured the Gospel so that it opens with a Christological declaration about God (1:1: the Logos was God) and closes with a human character making the same confession. The inclusion is deliberate.</p>',
    "29": '<p><strong>ὅτι ἑώρακάς με πεπίστευκας</strong> -- "because you have seen me you have believed" -- perfect tenses for both verbs: the seeing is a completed act, the believing a continuing state. The beatitude that follows -- <em>makarioi hoi mē idontes kai pisteusantes</em> -- "blessed those who have not seen and yet have believed" -- is addressed beyond the narrative to the Evangelist\'s readers, who cannot see the risen Jesus. It is the Gospel\'s explicit gesture toward its audience.</p>',
    "30": '<p><strong>πολλὰ μὲν οὖν καὶ ἄλλα σημεῖα</strong> -- "many other signs also." The Evangelist explicitly acknowledges selectivity. He has chosen the signs he has recorded; others exist that are not written. The word <em>sēmeia</em> (signs) is the Evangelist\'s characteristic term for Jesus\'s works -- pointing beyond themselves to something about the one who performs them.</p>',
    "31": '<p><strong>ταῦτα δὲ γέγραπται ἵνα πιστεύ[σ]ητε</strong> -- "these are written so that you may believe." The Evangelist states his purpose in writing. The verb has two major manuscript variants: <em>pisteusēte</em> (aorist subjunctive: come to believe, initial faith) and <em>pisteūēte</em> (present subjunctive: continue believing, sustained faith). Both are well-attested. The aorist reading supports a mission to outsiders; the present supports an address to believers. The Gospel serves both; the ambiguity may be intentional.</p><p><strong>ζωὴν ἔχητε ἐν τῷ ὀνόματι αὐτοῦ</strong> -- life in his name. The goal of belief is life; the means is the name -- the revealed character of Jesus as Messiah and Son of God. The Gospel ends on the term that opened it: life (<em>zōē</em>) in 1:4 was in the Logos; in 20:31 it is the goal of writing the Gospel.</p>'
  },
  "21": {
    "1": '<p><strong>ἐπὶ τῆς θαλάσσης τῆς Τιβεριάδος</strong> -- the Sea of Tiberias (= Sea of Galilee, named for the emperor). The return to Galilee recalls the setting of the earliest calls to discipleship (1:43). The chapter is widely regarded as an epilogue added to the original Gospel (which ends with 20:30-31), but internal vocabulary and style are consistent with the rest of the Gospel. The phrase <em>ephanerōsen palin</em> -- "appeared again" -- signals a third manifestation; the Evangelist counts appearances (cf. v.14).</p>',
    "2": '<p>Seven disciples are named. The number seven has symbolic weight in the Gospel (seven signs, seven "I am" sayings) and may not be incidental. Thomas and Nathanael appear together, as at key moments (1:45-51; 11:16). The Zebedee brothers are named only here in the Fourth Gospel -- John is never named directly in his own Gospel.</p>',
    "3": '<p><strong>ὑπάγω ἁλιεύειν</strong> -- "I am going fishing." Peter\'s statement is characteristically decisive. Whether this represents a return to the pre-call life or simply practical activity during the interval is debated. The Evangelist does not editorialize. <strong>ἐν ἐκείνῃ τῇ νυκτὶ ἐπίασαν οὐδέν</strong> -- "that night they caught nothing" -- prepares for the abundance that the risen Jesus provides.</p>',
    "4": '<p><strong>οὐ μέντοι ᾔδεισαν οἱ μαθηταὶ ὅτι Ἰησοῦς ἐστιν</strong> -- "the disciples did not know it was Jesus." Non-recognition is a pattern in the resurrection appearances (20:14; Luke 24:16). The Evangelist again notes the non-recognition without explaining it. The physical setting -- shore at dawn, distance across the water -- may account for it practically.</p>',
    "5": '<p><strong>Παιδία</strong> -- "Children" (or "lads") -- a vocative address that appears nowhere else in the Gospel proper. It is a familiar term of address; the disciples do not yet recognize the speaker. The question about food (<em>prosphagion</em>, a relish or condiment eaten with bread) sets up the contrast with the miraculous provision to follow.</p>',
    "6": '<p><strong>εἰς τὰ δεξιά</strong> -- "on the right side" -- the miracle is the identification signal that triggers recognition in v.7. The parallel with the miraculous catch in Luke 5:1-11 is structurally close but distinct in context: that was the call to discipleship; this is restoration after the crucifixion.</p>',
    "7": '<p><strong>ὁ κύριός ἐστιν</strong> -- "It is the Lord!" The Beloved Disciple is again the first to perceive who Jesus is (cf. 20:8). Peter\'s response -- wrapping his outer garment around him (for he was stripped for work) and jumping into the sea -- is impulsive action rather than reflection. The parenthetical explanation of his nakedness (<em>ēn gar gymnos</em>) is the kind of detail the Evangelist attributes to eyewitness memory.</p>',
    "8": '<p>Brief connector. The other disciples come in the boat, dragging the net. The Evangelist notes the distance -- about two hundred cubits (roughly a hundred yards) -- with the precision of a source who was present.</p>',
    "9": '<p><strong>ἀνθρακιάν</strong> -- "a fire of coals" (<em>anthrakian</em>). The word occurs only twice in the NT -- here and at 18:18, where Peter stood warming himself at a coal fire in the high priest\'s courtyard when he denied Jesus. The repetition is almost certainly deliberate: the scene of Peter\'s restoration mirrors the scene of Peter\'s denial, with the coal fire as the common detail.</p>',
    "10": '<p>Jesus calls for fish from the catch the disciples have just made -- not only from what he has already prepared. The invitation to bring their fish and add it to his provision mirrors the feeding miracle logic (6:9-11) where Jesus takes what is offered.</p>',
    "11": '<p><strong>ἑκατὸν πεντήκοντα τρία</strong> -- 153 fish. Several explanations have been proposed: Jerome noted that ancient naturalists counted 153 species of fish, symbolizing the universality of the mission; mathematically, 153 is the triangular number of 17 (sum of 1 through 17), and 17 = 10 + 7 (completeness). None of these are excluded, but the Evangelist\'s primary interest may be in the precision itself -- the count is what you remember when you were there and counted. The unbroken net despite the number is noted without explanation.</p>',
    "12": '<p><strong>οὐδεὶς ἐτόλμα τῶν μαθητῶν ἐξετάσαι αὐτόν</strong> -- "none of the disciples dared ask him, Who are you?" They knew it was the Lord. The combination of knowing and not asking creates a charged, awed atmosphere. The recognition is certain but the encounter is not ordinary -- there is a quality to the risen Jesus that makes the question superfluous and also somehow not entirely possible.</p>',
    "13": '<p><strong>ἔρχεται Ἰησοῦς καὶ λαμβάνει τὸν ἄρτον καὶ δίδωσιν αὐτοῖς</strong> -- "Jesus comes and takes the bread and gives it to them" -- the same verb sequence as 6:11 at the feeding of the five thousand. The eucharistic resonance is available without the Evangelist making it explicit; the vocabulary of taking, giving, and distributing recalls both the feeding miracle and the Last Supper.</p>',
    "14": '<p><strong>τρίτον ἐφανερώθη Ἰησοῦς</strong> -- "the third time Jesus was manifested" -- the Evangelist counts appearances. The passive <em>ephanerōthē</em> (was manifested) places the initiative with Jesus; the disciples receive manifestation rather than discovering him. The counting underlines that the resurrection is a series of historical encounters, not an enduring visionary state.</p>',
    "15": '<p><strong>ἀγαπᾷς με πλέον τούτων</strong> -- "do you love me more than these?" The comparative <em>pleon toutōn</em> recalls Peter\'s boast (13:37: "I will lay down my life for you") and his implied superiority over the other disciples. Jesus uses <em>agapas</em> (<em>agapaō</em>, G25); Peter replies with <em>philō</em> (<em>phileō</em>, G5368). The glossary entries preserve the traditional distinction -- <em>agapaō</em> as deliberate, principled love; <em>phileō</em> as warm personal affection -- though many scholars argue John uses the terms synonymously elsewhere. What the Evangelist preserves is that Jesus asks one kind of love and Peter answers with another. Commission: <em>boske ta arnia mou</em> -- "feed my lambs" (<em>boskein</em>, tend/pasture; <em>arnia</em>, young lambs).</p>',
    "16": '<p>The second exchange. Jesus repeats with <em>agapas</em> but drops "more than these" -- the comparison is no longer raised. Peter replies again with <em>philō</em>. The commission shifts: <em>poimaine ta probata mou</em> -- "shepherd my sheep" (<em>poimainein</em>, shepherd/govern; <em>probata</em>, sheep). The verb changes from <em>boskein</em> (feed/tend) to <em>poimainein</em> (shepherd/govern) -- the pastoral image broadens from feeding to leadership.</p>',
    "17": '<p><strong>λέγει αὐτῷ τὸ τρίτον Φιλεῖς με</strong> -- "he says to him the third time, Do you love me?" On the third asking, Jesus shifts to Peter\'s own word -- <em>Phileis</em>. The change explains Peter\'s pain: Jesus seemed now to be doubting the personal affection Peter had claimed. The Evangelist records this emotional detail (<em>elupēthē ho Petros</em>, Peter was grieved) without sentimentalizing it.</p><p>The three-fold commissioning explicitly restores Peter after the three-fold denial (18:17, 25, 27). The parallel is structural -- the Evangelist builds it into the scene deliberately. The final commission returns to the verb <em>boskein</em> (<em>boske ta probata mou</em>), forming a bracket with v.15.</p>',
    "18": '<p><strong>ἐκτενεῖς τὰς χεῖράς σου</strong> -- "you will stretch out your hands" -- the phrase is used in Greek for the outstretched arms of crucifixion. The Evangelist\'s editorial note in v.19 confirms this reading. The contrast with youth (<em>neōteros</em>, when you girded yourself and walked where you wished) and old age (when another will gird you and lead you where you do not wish) describes the loss of self-determination. The three pairs of clauses form an antithetical structure of freedom and its surrender.</p>',
    "19": '<p><strong>ποίῳ θανάτῳ δοξάσει τὸν θεόν</strong> -- "by what kind of death he would glorify God." The Evangelist\'s interpretive note uses the same formula as 12:33 and 18:32 (<em>poiō thanatō</em> -- what kind of death). The formula signals a predictive speech act that has been or will be fulfilled. Peter\'s death glorifies God -- not merely submits to God, but actively glorifies, as Jesus\'s death glorified the Father (17:1). The command <em>Akolouthei moi</em> -- "Follow me" -- carries the full freight of what following means in John 12:25-26.</p>',
    "20": '<p><strong>τὸν μαθητὴν ὃν ἠγάπα ὁ Ἰησοῦς</strong> -- the designation of the Beloved Disciple is introduced again with a detail that ties him to the Last Supper (<em>en tō deinpō</em>, at the supper; <em>anepesen epi to stēthos autou</em>, leaned on his chest, 13:23-25). The Evangelist locates the Beloved Disciple in this climactic scene with precision -- already following, already there. Peter asks about him.</p>',
    "21": '<p><strong>οὗτος δὲ τί</strong> -- "but what about this man?" Peter\'s question is natural after receiving a personal prediction of martyrdom. Jesus\'s answer deflects it entirely. The Evangelist uses the scene to draw a distinction between Peter\'s calling (follow; the call to martyrdom) and the Beloved Disciple\'s (bearing witness, v.24).</p>',
    "22": '<p><strong>ἐὰν αὐτὸν θέλω μένειν ἕως ἔρχομαι</strong> -- "if I want him to remain until I come, what is that to you?" The conditional <em>ean</em> with subjunctive expresses a hypothetical: Jesus does not assert that the Beloved Disciple will remain. The emphasis falls on the final words to Peter: <em>su moi akolouthei</em> -- "you, follow me." Peter\'s calling is unaffected by another disciple\'s different calling. The personal address (<em>su moi</em>) isolates Peter -- this is his commission, regardless of another\'s.</p>',
    "23": '<p><strong>οὐκ εἶπεν δὲ αὐτῷ ὁ Ἰησοῦς ὅτι οὐκ ἀποθνῄσκει</strong> -- "Jesus did not say that he would not die." The Evangelist corrects a misreading that had circulated in the community -- the rumor that the Beloved Disciple would not die before the Parousia. The clarification is careful: Jesus said only a conditional ("if I want him to remain"), which is not a promise of longevity. The correction is best explained by the death of the Beloved Disciple -- or his approaching death -- making the rumor a live issue in the community.</p>',
    "24": '<p><strong>ὁ γράψας ταῦτα</strong> -- "the one who wrote these things." The Evangelist identifies the Beloved Disciple as the author of the Gospel (<em>ho martyrei... ho grapsas</em>, the one who testifies... who wrote). The "we know" (<em>oidamen</em>) that follows is a communal certification, distinct from the Beloved Disciple\'s first-person authority. The community attests the truth of his witness. This double layer of testimony (author\'s and community\'s) functions like a colophon.</p>',
    "25": '<p><strong>οἶμαι δὲ οὐδὲ αὐτὸν τὸν κόσμον χωρῆσαι τὰ γραφόμενα βιβλία</strong> -- "I suppose the world itself would not contain the books that would be written." The Evangelist closes with a first-person singular (<em>oimai</em>, I suppose) -- the only occurrence in the Gospel, strengthening the case that the Beloved Disciple is speaking directly. The hyperbole is a rhetorical <em>adynaton</em>, asserting the inexhaustibility of what Jesus did and said. A similar device closes Eccl 12:12. The Evangelist ends not with closure but with abundance -- more than can be contained.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'john')
    merge_comm(existing, JOHN)
    save_comm('mkt-original', 'john', existing)
    print('John 19-21 mkt-original written.')

if __name__ == '__main__':
    main()
